    type_: Annotated[Optional[WhereEqUserType], Field(alias="type")] = None
    """
    Matches the user type.
    """
    typename__: Annotated[Optional[Literal["WhereUser"]], Field(alias="__typename")] = (
        "WhereUser"
    )


